      "mainEntity": [
        {
          "@type": "Question",
          "name": "How is a backlog of unrecorded transactions brought up to date?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Work backwards from bank statements, which capture nearly every transaction, then match them to invoices, purchase bills and cash vouchers month by month. Opening balances are agreed to the last audited or filed figures, GST and TDS returns are reconciled, and each month is closed and locked before the next is started. Missing bills are listed for collection."
          }
        },
        {
          "@type": "Question",
          "name": "What is the difference between catch-up bookkeeping and clean-up bookkeeping?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Catch-up bookkeeping records transactions for periods where nothing was entered, while clean-up bookkeeping corrects entries that exist but are wrong, such as duplicate ledgers, misposted GST or a suspense account that never cleared. A business two years behind needs catch-up; a business whose Tally file will not tie to the bank needs clean-up."
          }
        },
        {
          "@type": "Question",
          "name": "What penalties apply when GST returns are filed late during a catch-up?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Late fee on GSTR-3B is Rs 50 a day, or Rs 20 a day for a nil return, subject to a turnover linked cap, plus interest at 18% a year on tax paid late. Input tax credit for a financial year cannot be claimed after 30 November of the following year, so a long backlog can permanently cost credit."
          }
        }
